-- Published Learning Hub lesson: Free Falling (Bowl + Orange catch game).
-- Workspace: /workspace?mission=first-move&lesson=lvl1-free-falling

insert into public.lms_lessons (id, payload, published)
values (
  'lvl1-free-falling',
  $payload$
{"id":"lvl1-free-falling","title":"Free Falling","summary":"Build a catch game: a Bowl at the bottom, a falling Orange, arrow-key movement, gravity, a Score variable, and a pop when you catch it.","bodyHtml":"<p>In <strong>Free Falling</strong> you use <strong>two sprites</strong>: a <strong>Bowl</strong> (catcher) and a falling object (we use <strong>Orange</strong> from the sprite catalog—you can swap for another costume). Work in the <strong>Motion</strong>, <strong>Control</strong>, <strong>Sensing</strong>, <strong>Variables</strong>, and <strong>Sound</strong> categories. Tap <strong>Run</strong> to try your game, and <strong>Save</strong> when you like it.</p><p><strong>How to read block colors</strong>: <span style=\"color:#FFBF00\"><strong>Events</strong></span> · <span style=\"color:#59C059\"><strong>Motion</strong></span> · <span style=\"color:#9966FF\"><strong>Looks</strong></span> · <span style=\"color:#FFAB19\"><strong>Control</strong></span> · <span style=\"color:#5CB1D6\"><strong>Sensing</strong></span> · <span style=\"color:#FF8C1A\"><strong>Variables</strong></span> · <span style=\"color:#CF63CF\"><strong>Sound</strong></span> · <span style=\"color:#59C059\"><strong>Numbers</strong></span> · <span style=\"color:#4C97FF\"><strong>Logic</strong></span>.</p>","skillLevel":1,"workspaceHref":"/workspace?mission=first-move&lesson=lvl1-free-falling","estimatedMinutes":32,"topic":"Games & stories","objective":"Sprites, loops & variables","levelName":"Beginner","roleLabel":"Learner","cardImageUrl":"/images/features-build-games-v2.png","modules":[{"id":"freefall-m1","title":"Set up your sprites","points":80,"durationMins":5,"steps":4,"detail":"<p>Add <strong>two sprites</strong> from the sprite library: pick <strong>Bowl</strong> for the catcher and <strong>Orange</strong> (or another fruit, star, or costume you like) for the falling object. Rename them so you can tell them apart.</p><p>On <strong>each</strong> sprite, add <span style=\"color:#FFBF00\"><strong>When Run clicked</strong></span> → <span style=\"color:#9966FF\"><strong>shrink by</strong></span> <span style=\"color:#59C059\"><strong>40</strong></span> (from <strong>Looks</strong>) so both fit the stage nicely—that brings size from 100% down toward 60%.</p>"},{"id":"freefall-m2","title":"Place the Bowl at the bottom","points":90,"durationMins":4,"steps":3,"detail":"<p>Select the <strong>Bowl</strong> sprite. Under <span style=\"color:#FFBF00\"><strong>When Run clicked</strong></span>, snap <span style=\"color:#59C059\"><strong>go to x: y:</strong></span> and plug in <span style=\"color:#59C059\"><strong>number</strong></span> blocks: <strong>x</strong> = <strong>0</strong>, <strong>y</strong> = <strong>−70</strong>.</p><p>That centers the Bowl near the <strong>bottom</strong> of the stage in Scratch-style coordinates, ready to slide left and right.</p>"},{"id":"freefall-m3","title":"Add left and right movement","points":100,"durationMins":6,"steps":5,"detail":"<p>Still on the <strong>Bowl</strong>, add a second stack (another hat is OK) or continue under the first—use <span style=\"color:#FFAB19\"><strong>forever</strong></span> from <strong>Control</strong>.</p><p>Inside the loop, use <span style=\"color:#4C97FF\"><strong>if</strong></span> with <span style=\"color:#5CB1D6\"><strong>key right arrow pressed?</strong></span> (from <strong>Sensing</strong>): in the <strong>then</strong> branch, <span style=\"color:#59C059\"><strong>change x by</strong></span> <span style=\"color:#59C059\"><strong>4</strong></span>. Add another <strong>if</strong> for <strong>key left arrow pressed?</strong> and <strong>change x by</strong> <span style=\"color:#59C059\"><strong>−4</strong></span>.</p><p>Tap <strong>Run</strong> and hold the arrow keys—the Bowl should glide smoothly.</p>"},{"id":"freefall-m4","title":"Make the object fall","points":110,"durationMins":7,"steps":5,"detail":"<p>On the <strong>Orange</strong> (falling) sprite, use <span style=\"color:#FFBF00\"><strong>When Run clicked</strong></span> → <span style=\"color:#FFAB19\"><strong>forever</strong></span>.</p><p>Inside: <span style=\"color:#59C059\"><strong>change y by</strong></span> <span style=\"color:#59C059\"><strong>−0.9</strong></span> each frame to simulate <strong>gravity</strong>. Then add <span style=\"color:#4C97FF\"><strong>if</strong></span> with <span style=\"color:#4C97FF\"><strong>compare</strong></span>: <span style=\"color:#5CB1D6\"><strong>y position</strong></span> <strong>&lt;</strong> <span style=\"color:#59C059\"><strong>−170</strong></span>. In <strong>then</strong>: <span style=\"color:#59C059\"><strong>go to</strong></span> <strong>random position</strong>, then <span style=\"color:#59C059\"><strong>set y to</strong></span> <span style=\"color:#59C059\"><strong>170</strong></span> so it respawns at the top and falls again.</p>"},{"id":"freefall-m5","title":"Create the Score variable","points":85,"durationMins":3,"steps":3,"detail":"<p>Open <span style=\"color:#FF8C1A\"><strong>Variables</strong></span> and click <strong>Make a variable</strong>. Name it <strong>Score</strong>.</p><p>On the <strong>Bowl</strong> (or either sprite), under <span style=\"color:#FFBF00\"><strong>When Run clicked</strong></span> before the game runs, add <span style=\"color:#FF8C1A\"><strong>set Score to</strong></span> <span style=\"color:#59C059\"><strong>0</strong></span>.</p>"},{"id":"freefall-m6","title":"Detect a catch and score","points":120,"durationMins":8,"steps":6,"detail":"<p>On the <strong>Orange</strong> sprite, add a <strong>second</strong> <span style=\"color:#FFAB19\"><strong>forever</strong></span> loop (two forever stacks both run together).</p><p>Inside this loop: <span style=\"color:#4C97FF\"><strong>if</strong></span> <span style=\"color:#5CB1D6\"><strong>touching Bowl?</strong></span> (pick <strong>Bowl</strong> in the menu). In <strong>then</strong>: <span style=\"color:#FF8C1A\"><strong>change Score by</strong></span> <span style=\"color:#59C059\"><strong>1</strong></span>, <span style=\"color:#CF63CF\"><strong>play sound</strong></span> <strong>pop</strong>, <span style=\"color:#59C059\"><strong>go to</strong></span> <strong>random position</strong>, and <span style=\"color:#59C059\"><strong>set y to</strong></span> <span style=\"color:#59C059\"><strong>180</strong></span> so the fruit resets above the stage.</p>"},{"id":"freefall-m7","title":"Test and play","points":95,"durationMins":4,"steps":3,"detail":"<p>Tap <strong>Run</strong>. Catch oranges with the Bowl and watch <strong>Score</strong> go up each time you hear <strong>pop</strong>.</p><p><strong>Save</strong> your adventure when you are happy—you built a real game!</p>"}]}
$payload$::jsonb,
  true
)
on conflict (id) do update set
  payload = excluded.payload,
  published = excluded.published,
  updated_at = now();
